const item = $input.first().json;
const body = $('Webhook').first().json.body || {};
const action = body.action || 'new';

if (action === 'edit') return [{ json: { action: 'edit', ...body } }];
if (action === 'add-line') return [{ json: { action: 'add-line', ...body } }];
return [{ json: { action: 'new', ...body } }];

const body = $input.first().json;
const code = body.action === 'edit' ? 0 : body.action === 'add-line' ? 1 : 2;
return [{ json: { ...body }, code }];

const html = $input.first().json.body;
const csrfMatch = html.match(/name="--form-session-key"\s+value="([^"]+)"/);
const origMatch = html.match(/name="--original_action"[^>]*value="([^"]+)"/);
return [{ json: { csrfToken: csrfMatch ? csrfMatch[1] : '', originalAction: origMatch ? origMatch[1] : 'edit' } }];

const route = $input.all()[0];
const webhook = $('Webhook').first().json.body || {};
const editFields = webhook.fields || {};
const csrf = $('Extract edit CSRF').first().json;

const params = {
  '-table': 'expense_vouchers',
  '-action': 'edit',
  'expense_voucher_id': webhook.expense_voucher_id,
  '__keys__[expense_voucher_id]': webhook.expense_voucher_id,
  '--original_action': csrf.originalAction,
  '--form-session-key': csrf.csrfToken,
  '_qf__existing_expense_vouchers_record_form': '1'
};

for (const [k, v] of Object.entries(editFields)) {
  params[k] = v;
}

return [{ json: params }];

const response = $input.first().json;
const bodyStr = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);
const saved = bodyStr.includes('saved') || response.statusCode === 302;
return [{ json: { success: saved, message: saved ? 'Expense voucher updated' : 'Edit may have failed', voucherId: $('Switch action').first().json.expense_voucher_id } }];

const body = $input.first().json;
const webhook = $('Webhook').first().json.body || {};
const line = webhook.line || {};
return [{ json: { ...body, ...webhook, line } }];

const data = $input.first().json;
const line = data.line || {};

const params = {
  '-table': 'expense_vouchers',
  '-relationship': 'expense_lines',
  '-action': 'new_related_record',
  'expense_voucher_id': data.expense_voucher_id,
  '__keys__[expense_voucher_id]': data.expense_voucher_id,
  'line_id': '',
  'expense_type_id': line.expense_type_id || '3',
  'description': line.description || '',
  'amount': line.amount || '',
  'trip_id': line.trip_id || '',
  'bill_details': line.bill_details || '',
  '_qf__expense_vouchers_expense_lines': '',
  '--original_action': 'new_related_record',
  '-Save': 'Save'
};

return [{ json: params }];

const response = $input.first().json;
const bodyStr = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);
const saved = bodyStr.includes('saved') || response.statusCode === 302;
return [{ json: { success: saved, message: saved ? 'Expense line added' : 'Add line may have failed', voucherId: $('Switch action').first().json.expense_voucher_id } }];

const html = $input.first().json.body;
const csrfMatch = html.match(/name="--form-session-key"\s+value="([^"]+)"/);
const csrfToken = csrfMatch ? csrfMatch[1] : '';
if (!csrfToken) throw new Error('Could not extract CSRF token from form');
return [{ json: { csrfToken } }];

const expense = $input.all()[0];
const webhookData = $('Webhook').first();
const fields = { ...expense.json };
if (webhookData.json.body) Object.assign(fields, webhookData.json.body);

const lines = fields.lines || [];
const formParams = {};
formParams['-table'] = 'expense_vouchers';
formParams['-action'] = 'new';
formParams['--form-session-key'] = fields.csrfToken;
formParams['--no-query'] = '1';
formParams['_qf__new_expense_vouchers_record_form'] = '1';
formParams['new_expense_vouchers_record_form'] = '1';

['expense_voucher_id','expense_date','ledger_date','employee_id','charge_to_customer','customer_id','order_id','default_expense_category','description'].forEach(f => {
  const val = fields[f];
  if (val !== undefined && val !== null && val !== '') formParams[f] = val;
});

let lineIndex = 0;
for (const line of lines) {
  const pfx = `lines[${lineIndex}]`;
  formParams[`${pfx}[expense_type]`] = line.expense_type || '';
  formParams[`${pfx}[description]`] = line.description || '';
  formParams[`${pfx}[bill_no]`] = line.bill_no || '';
  formParams[`${pfx}[trip]`] = line.trip || '';
  formParams[`${pfx}[amount]`] = line.amount || '';
  formParams[`${pfx}[__id__]`] = 'new';
  lineIndex++;
}
if (lines.length === 0) formParams['lines[0][__id__]'] = 'new';
formParams['lines[__loaded__]'] = String(lineIndex || 1);
return [{ json: formParams }];

const response = $input.first().json;
const bodyStr = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);
const success = bodyStr.includes('expense_voucher_id') || bodyStr.includes('Record saved') || bodyStr.includes('successfully saved');
const idMatch = bodyStr.match(/expense_voucher_id=(\d+)/);
return [{ json: { success, expenseVoucherId: idMatch ? idMatch[1] : null, message: success ? 'Expense voucher submitted' : 'Submission may have failed' } }];
